1	import { useState, useEffect, useRef } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	import { useToast } from "@/hooks/use-toast";
5	import { motion, AnimatePresence } from "framer-motion";
6	import KiraMessage from "@/components/onboarding/KiraMessage";
7	import UserResponse from "@/components/onboarding/UserResponse";
8	import OptionButtons from "@/components/onboarding/OptionButtons";
9	import TypingIndicator from "@/components/onboarding/TypingIndicator";
10	import OnboardingHeader from "@/components/onboarding/OnboardingHeader";
11	import TextInput from "@/components/onboarding/TextInput";
12	
13	
14	// Creator flow steps
15	const creatorSteps = [
16	  {
17	    id: "welcome",
18	    kiraMessage: (name: string, _?: string) => `Hi 👋 ${name || "there"}! I'm Kira, your creative companion at Crevia. I'm so excited to meet you! Let's go through a few quick steps so I can personalize your experience. Ready?`,
19	    options: [
20	      { label: "Let's do this! 🚀", value: "ready" },
21	      { label: "Sure thing! ✨", value: "ready" }
22	    ],
23	    type: "options" as const
24	  },
25	  {
26	    id: "creator_type",
27	    kiraMessage: (_?: string, __?: string) => "Amazing! First things first — what kind of creator are you? Pick all that fit you 🎨",
28	    options: [
29	      { label: "Content Creator", value: "content_creator" },
30	      { label: "UGC Creator", value: "ugc_creator" },
31	      { label: "Coach / Educator", value: "coach" },
32	      { label: "Designer", value: "designer" },
33	      { label: "Photographer", value: "photographer" },
34	      { label: "Videographer", value: "videographer" },
35	      { label: "Writer", value: "writer" },
36	      { label: "Influencer", value: "influencer" },
37	      { label: "Other", value: "other" }
38	    ],
39	    type: "multi-select" as const,
40	    hasOther: true
41	  },
42	  {
43	    id: "goals",
44	    kiraMessage: (_?: string, __?: string) => "Love it! 💪 Now tell me — what are you hoping to achieve with Crevia?",
45	    options: [
46	      { label: "Find brand deals 💰", value: "brand_deals" },
47	      { label: "Earn from my skills 💼", value: "earn_skills" },
48	      { label: "Grow my audience 📈", value: "grow_audience" },
49	      { label: "Build my personal brand ✨", value: "personal_brand" },
50	      { label: "Organize my workflow 📋", value: "workflow" },
51	      { label: "Other", value: "other" }
52	    ],
53	    type: "multi-select" as const,
54	    hasOther: true
55	  },
56	  {
57	    id: "handle",
58	    kiraMessage: (_?: string, __?: string) => "Awesome goals! 🎯 Now let's set up your Crevia Link. What should your username be? This will be your public profile URL (crevia.app/yourname)",
59	    type: "text" as const,
60	    placeholder: "yourname",
61	    prefix: "crevia.app/"
62	  },
63	  {
64	    id: "bio",
65	    kiraMessage: (_, handle: string) => `Nice choice, @${handle}! 🌟 Now write a short bio to introduce yourself to brands and other creators. Keep it snappy!`,
66	    type: "textarea" as const,
67	    placeholder: "I'm a creative soul who loves...",
68	    optional: true
69	  },
70	  {
71	    id: "complete",
72	    kiraMessage: (name: string, _?: string) => `You're officially part of the Crevia family, ${name || "friend"}! 🎉\n\nI've set up your profile and I'm ready to help you find amazing opportunities, grow your audience, and make your creative dreams come true.\n\nLet's go make some magic happen! ✨🦁`,
73	    type: "final" as const
74	  }
75	];
76	
77	// Brand flow steps
78	const brandSteps = [
79	  {
80	    id: "welcome",
81	    kiraMessage: (name: string, _?: string) => `Hey there 👋 ${name || ""}! I'm Kira, and I'll be helping you discover amazing creators for your brand. Let's set up your profile real quick!`,
82	    options: [
83	      { label: "Let's get started! 🚀", value: "ready" },
84	      { label: "Sounds good! ✨", value: "ready" }
85	    ],
86	    type: "options" as const
87	  },
88	  {
89	    id: "business_type",
90	    kiraMessage: (_?: string, __?: string) => "First up — what type of business are you? 🏢",
91	    options: [
92	      { label: "Startup", value: "startup" },
93	      { label: "Agency", value: "agency" },
94	      { label: "Company", value: "company" },
95	      { label: "Corporate", value: "corporate" },
96	      { label: "NGO", value: "ngo" },
97	      { label: "Other", value: "other" }
98	    ],
99	    type: "single-select" as const,
100	    hasOther: true
101	  },
102	  {
103	    id: "goals",
104	    kiraMessage: (_?: string, __?: string) => "Perfect! 💼 What are you hoping to achieve with Crevia?",
105	    options: [
106	      { label: "Discover creators faster 🔍", value: "discover_creators" },
107	      { label: "Run organized campaigns 📊", value: "campaigns" },
108	      { label: "Track performance 📈", value: "analytics" },
109	      { label: "Scale UGC operations 🎬", value: "ugc" },
110	      { label: "Build creator relationships 🤝", value: "relationships" },
111	      { label: "Other", value: "other" }
112	    ],
113	    type: "multi-select" as const,
114	    hasOther: true
115	  },
116	  {
117	    id: "brand_name",
118	    kiraMessage: (_?: string, __?: string) => "Exciting goals! 🎯 What's your brand name?",
119	    type: "text" as const,
120	    placeholder: "Your Brand Name"
121	  },
122	  {
123	    id: "handle",
124	    kiraMessage: (_?: string, brandName?: string) => `${brandName || "Your brand"} — love it! 💜 Now let's pick your Crevia handle. This will be your public profile where creators can learn about you.`,
125	    type: "text" as const,
126	    placeholder: "yourbrand",
127	    prefix: "crevia.app/"
128	  },
129	  {
130	    id: "description",
131	    kiraMessage: (_?: string, __?: string) => "Almost there! Write a quick description about your brand so creators know who you are 📝",
132	    type: "textarea" as const,
133	    placeholder: "We're a brand that...",
134	    optional: true
135	  },
136	  {
137	    id: "complete",
138	    kiraMessage: (name: string, _?: string) => `Welcome to Crevia, ${name || "friend"}! 🎉\n\nYour brand profile is all set up. I'm here to help you find the perfect creators for your campaigns and make collaboration seamless.\n\nLet's build something amazing together! 🦁✨`,
139	    type: "final" as const
140	  }
141	];
142	
143	interface Message {
144	  id: string;
145	  type: "kira" | "user";
146	  content: string;
147	  timestamp: Date;
148	}
149	
150	const KiraOnboarding = () => {
151	  const navigate = useNavigate();
152	  const { toast } = useToast();
153	  const chatEndRef = useRef<HTMLDivElement>(null);
154	  
155	  const [userType, setUserType] = useState<"creator" | "brand" | null>(null);
156	  const [userName, setUserName] = useState("");
157	  const [userId, setUserId] = useState<string | null>(null);
158	  const [currentStep, setCurrentStep] = useState(0);
159	  const [messages, setMessages] = useState<Message[]>([]);
160	  const [isTyping, setIsTyping] = useState(false);
161	  const [selectedOptions, setSelectedOptions] = useState<string[]>([]);
162	  const [textInput, setTextInput] = useState("");
163	  const [otherText, setOtherText] = useState("");
164	  const [showOtherInput, setShowOtherInput] = useState(false);
165	  const [isLoading, setIsLoading] = useState(true);
166	  
167	  // Collected data
168	  const [collectedData, setCollectedData] = useState<Record<string, any>>({});
169	
170	  const steps = userType === "creator" ? creatorSteps : brandSteps;
171	  const currentStepData = steps[currentStep];
172	
173	  // Auto-scroll to bottom
174	  useEffect(() => {
175	    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
176	  }, [messages, isTyping]);
177	
178	  // Initialize - get user data
179	  useEffect(() => {
180	    const initUser = async () => {
181	      const { data: { session } } = await supabase.auth.getSession();
182	      
183	      if (!session) return;
184	
185	      setUserId(session.user.id);
186	      
187	      // Get user's name from metadata
188	      const fullName = session.user.user_metadata?.full_name || 
189	                       session.user.user_metadata?.name ||
190	                       session.user.email?.split("@")[0] || "";
191	      const firstName = fullName.split(" ")[0];
192	      setUserName(firstName);
193	
194	      // Check if user already has a profile with user_type
195	      const { data: profile } = await supabase
196	        .from("profiles")
197	        .select("user_type, handle, bio, display_name")
198	        .eq("id", session.user.id)
199	        .single();
200	
201	      if (profile?.user_type) {
202	        // Check if onboarding is already complete by checking creator/brand profiles
203	        let onboardingComplete = false;
204	        
205	        if (profile.user_type === "creator") {
206	          const { data: creatorProfile } = await supabase
207	            .from("creator_profiles")
208	            .select("id, creator_types")
209	            .eq("profile_id", session.user.id)
210	            .single();
211	          onboardingComplete = !!(creatorProfile?.creator_types && creatorProfile.creator_types.length > 0);
212	        } else if (profile.user_type === "brand") {
213	          const { data: brandProfile } = await supabase
214	            .from("brand_profiles")
215	            .select("id, business_type")
216	            .eq("profile_id", session.user.id)
217	            .single();
218	          onboardingComplete = !!brandProfile?.business_type;
219	        }
220	
221	        if (onboardingComplete) {
222	          navigate("/dashboard");
223	          return;
224	        }
225	        
226	        setUserType(profile.user_type as "creator" | "brand");
227	      }
228	      
229	      setIsLoading(false);
230	    };
231	
232	    initUser();
233	  }, [navigate]);
234	
235	  // Start conversation when userType is set
236	  useEffect(() => {
237	    if (userType && !isLoading && messages.length === 0) {
238	      showKiraMessage(0);
239	    }
240	  }, [userType, isLoading]);
241	
242	  const showKiraMessage = async (stepIndex: number) => {
243	    const step = steps[stepIndex];
244	    if (!step) return;
245	
246	    setIsTyping(true);
247	    
248	    // Simulate typing delay
249	    await new Promise(resolve => setTimeout(resolve, 1000 + Math.random() * 1000));
250	    
251	    let messageContent = "";
252	    if (step.id === "welcome") {
253	      messageContent = step.kiraMessage(userName);
254	    } else if (step.id === "bio") {
255	      messageContent = step.kiraMessage(userName, collectedData.handle || "");
256	    } else if (step.id === "handle" && userType === "brand") {
257	      messageContent = step.kiraMessage(userName, collectedData.brand_name || "");
258	    } else if (step.id === "complete") {
259	      messageContent = step.kiraMessage(userName);
260	    } else {
261	      messageContent = step.kiraMessage(userName);
262	    }
263	
264	    setMessages(prev => [...prev, {
265	      id: `kira-${stepIndex}-${Date.now()}`,
266	      type: "kira",
267	      content: messageContent,
268	      timestamp: new Date()
269	    }]);
270	    
271	    setIsTyping(false);
272	    setSelectedOptions([]);
273	    setTextInput("");
274	    setOtherText("");
275	    setShowOtherInput(false);
276	  };
277	
278	  const handleOptionSelect = (value: string) => {
279	    if (currentStepData?.type === "single-select" || currentStepData?.type === "options") {
280	      if (value === "other" && currentStepData.hasOther) {
281	        setShowOtherInput(true);
282	        setSelectedOptions([value]);
283	      } else {
284	        setSelectedOptions([value]);
285	        if (!currentStepData.hasOther || value !== "other") {
286	          setTimeout(() => handleContinue([value]), 300);
287	        }
288	      }
289	    } else if (currentStepData?.type === "multi-select") {
290	      if (value === "other" && currentStepData.hasOther) {
291	        setShowOtherInput(!showOtherInput);
292	        if (selectedOptions.includes(value)) {
293	          setSelectedOptions(prev => prev.filter(v => v !== value));
294	        } else {
295	          setSelectedOptions(prev => [...prev, value]);
296	        }
297	      } else {
298	        if (selectedOptions.includes(value)) {
299	          setSelectedOptions(prev => prev.filter(v => v !== value));
300	        } else {
301	          setSelectedOptions(prev => [...prev, value]);
302	        }
303	      }
304	    }
305	  };
306	
307	  const handleContinue = async (options?: string[]) => {
308	    const finalOptions = options || selectedOptions;
309	    
310	    if (currentStepData?.type === "multi-select" && finalOptions.length === 0) {
311	      toast({ title: "Please select at least one option! 🎯" });
312	      return;
313	    }
314	
315	    let userResponseText = "";
316	    let dataToStore: any = finalOptions;
317	
318	    if (currentStepData?.type === "options" || currentStepData?.type === "single-select") {
319	      const selectedOption = currentStepData.options?.find(o => o.value === finalOptions[0]);
320	      userResponseText = selectedOption?.label || finalOptions[0];
321	      dataToStore = finalOptions[0];
322	    } else if (currentStepData?.type === "multi-select") {
323	      const selectedLabels = finalOptions.map(v => {
324	        const option = currentStepData.options?.find(o => o.value === v);
325	        return option?.label || v;
326	      });
327	      if (showOtherInput && otherText && finalOptions.includes("other")) {
328	        selectedLabels.push(otherText);
329	        dataToStore = [...finalOptions.filter(v => v !== "other"), otherText];
330	      }
331	      userResponseText = selectedLabels.join(", ");
332	    } else if (currentStepData?.type === "text" || currentStepData?.type === "textarea") {
333	      if (!textInput.trim() && !currentStepData.optional) {
334	        toast({ title: "Please enter something! ✏️" });
335	        return;
336	      }
337	      userResponseText = currentStepData.prefix ? `${currentStepData.prefix}${textInput}` : textInput;
338	      dataToStore = textInput.trim();
339	    }
340	
341	    // Add user response to messages
342	    if (userResponseText) {
343	      setMessages(prev => [...prev, {
344	        id: `user-${currentStep}-${Date.now()}`,
345	        type: "user",
346	        content: userResponseText,
347	        timestamp: new Date()
348	      }]);
349	    }
350	
351	    // Store collected data
352	    setCollectedData(prev => ({
353	      ...prev,
354	      [currentStepData?.id || ""]: dataToStore
355	    }));
356	
357	    // Move to next step
358	    const nextStep = currentStep + 1;
359	    
360	    if (nextStep < steps.length) {
361	      setCurrentStep(nextStep);
362	      setTimeout(() => showKiraMessage(nextStep), 500);
363	    }
364	  };
365	
366	  const handleComplete = async () => {
367	    if (!userId) return;
368	
369	    try {
370	      // Update profile with collected data
371	      const profileUpdate: any = {
372	        handle: collectedData.handle || userName.toLowerCase(),
373	        bio: collectedData.bio || collectedData.description || null,
374	        display_name: collectedData.brand_name || userName,
375	      };
376	
377	      const { error: profileError } = await supabase
378	        .from("profiles")
379	        .update(profileUpdate)
380	        .eq("id", userId);
381	
382	      if (profileError) throw profileError;
383	
384	      // Update creator or brand specific profile
385	      if (userType === "creator") {
386	        const { data: existingCreator } = await supabase
387	          .from("creator_profiles")
388	          .select("id")
389	          .eq("profile_id", userId)
390	          .single();
391	
392	        if (existingCreator) {
393	          await supabase
394	            .from("creator_profiles")
395	            .update({
396	              creator_types: collectedData.creator_type || [],
397	              goals: collectedData.goals || []
398	            })
399	            .eq("profile_id", userId);
400	        } else {
401	          await supabase
402	            .from("creator_profiles")
403	            .insert({
404	              profile_id: userId,
405	              creator_types: collectedData.creator_type || [],
406	              goals: collectedData.goals || []
407	            });
408	        }
409	      } else if (userType === "brand") {
410	        const { data: existingBrand } = await supabase
411	          .from("brand_profiles")
412	          .select("id")
413	          .eq("profile_id", userId)
414	          .single();
415	
416	        if (existingBrand) {
417	          await supabase
418	            .from("brand_profiles")
419	            .update({
420	              business_type: collectedData.business_type || null,
421	              goals: collectedData.goals || [],
422	              company_description: collectedData.description || null
423	            })
424	            .eq("profile_id", userId);
425	        } else {
426	          await supabase
427	            .from("brand_profiles")
428	            .insert({
429	              profile_id: userId,
430	              business_type: collectedData.business_type || null,
431	              goals: collectedData.goals || [],
432	              company_description: collectedData.description || null
433	            });
434	        }
435	      }
436	
437	      toast({ title: "Welcome to Crevia! 🎉" });
438	      navigate("/dashboard");
439	    } catch (error) {
440	      console.error("Error saving profile:", error);
441	      toast({ 
442	        title: "Oops! Something went wrong 😅", 
443	        description: "Please try again.",
444	        variant: "destructive" 
445	      });
446	    }
447	  };
448	
449	  // User type selection screen
450	  if (!userType && !isLoading) {
451	    return (
452	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center p-4">
453	        <motion.div 
454	          initial={{ opacity: 0, y: 20 }}
455	          animate={{ opacity: 1, y: 0 }}
456	          className="w-full max-w-lg text-center"
457	        >
458	           <div className="mb-8">
459	             <motion.div 
460	               initial={{ scale: 0 }}
461	               animate={{ scale: 1 }}
462	               transition={{ type: "spring", delay: 0.2 }}
463	               className="w-24 h-24 mx-auto mb-6 relative"
464	             >
465	               <motion.div
466	                 animate={{ scale: [1, 1.2, 1] }}
467	                 transition={{ repeat: Infinity, duration: 2 }}
468	                 className="text-5xl flex items-center justify-center w-full h-full"
469	               >
470	                 👋
471	               </motion.div>
472	             </motion.div>
473	            <h1 className="font-vollkorn text-3xl md:text-4xl font-bold mb-3">
474	              Hey {userName || "there"}! 
475	            </h1>
476	            <p className="text-muted-foreground text-lg">
477	              I'm Kira. Before we begin, are you joining as a...
478	            </p>
479	          </div>
480	
481	          <div className="grid grid-cols-2 gap-4">
482	            <motion.button
483	              whileHover={{ scale: 1.02 }}
484	              whileTap={{ scale: 0.98 }}
485	              onClick={() => handleUserTypeSelect("creator")}
486	              className="p-6 rounded-2xl bg-card border-2 border-transparent hover:border-bronze transition-all group"
487	            >
488	              <div className="text-4xl mb-3">🎨</div>
489	              <h3 className="font-vollkorn text-xl font-bold mb-1 group-hover:text-bronze transition-colors">Creator</h3>
490	              <p className="text-sm text-muted-foreground">Sell products & services</p>
491	            </motion.button>
492	
493	            <motion.button
494	              whileHover={{ scale: 1.02 }}
495	              whileTap={{ scale: 0.98 }}
496	              onClick={() => handleUserTypeSelect("brand")}
497	              className="p-6 rounded-2xl bg-card border-2 border-transparent hover:border-bronze transition-all group"
498	            >
499	              <div className="text-4xl mb-3">🏢</div>
500	              <h3 className="font-vollkorn text-xl font-bold mb-1 group-hover:text-bronze transition-colors">Brand</h3>
501	              <p className="text-sm text-muted-foreground">Find & hire creators</p>
502	            </motion.button>
503	          </div>
504	        </motion.div>
505	      </div>
506	    );
507	  }
508	
509	  const handleUserTypeSelect = async (type: "creator" | "brand") => {
510	    if (!userId) return;
511	    
512	    // Save user type to profile
513	    await supabase
514	      .from("profiles")
515	      .update({ user_type: type })
516	      .eq("id", userId);
517	    
518	    setUserType(type);
519	  };
520	
521	  if (isLoading) {
522	    return (
523	      <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex items-center justify-center">
524	        <motion.div
525	          animate={{ rotate: 360 }}
526	          transition={{ repeat: Infinity, duration: 1, ease: "linear" }}
527	          className="w-12 h-12 border-3 border-bronze border-t-transparent rounded-full"
528	        />
529	      </div>
530	    );
531	  }
532	
533	  const progress = ((currentStep + 1) / steps.length) * 100;
534	
535	  return (
536	    <div className="min-h-screen bg-gradient-to-br from-background via-bronze/5 to-background flex flex-col">
537	      <OnboardingHeader progress={progress} />
538	      
539	      {/* Chat Container */}
540	      <div className="flex-1 overflow-y-auto px-4 py-6 pb-32">
541	        <div className="max-w-2xl mx-auto space-y-4">
542	          <AnimatePresence mode="popLayout">
543	            {messages.map((message) => (
544	              <motion.div
545	                key={message.id}
546	                initial={{ opacity: 0, y: 20, scale: 0.95 }}
547	                animate={{ opacity: 1, y: 0, scale: 1 }}
548	                exit={{ opacity: 0, y: -10 }}
549	                transition={{ type: "spring", damping: 25, stiffness: 300 }}
550	              >
551	                {message.type === "kira" ? (
552	                  <KiraMessage content={message.content} />
553	                ) : (
554	                  <UserResponse content={message.content} />
555	                )}
556	              </motion.div>
557	            ))}
558	          </AnimatePresence>
559	
560	          {isTyping && (
561	            <motion.div
562	              initial={{ opacity: 0, y: 10 }}
563	              animate={{ opacity: 1, y: 0 }}
564	            >
565	              <TypingIndicator />
566	            </motion.div>
567	          )}
568	
569	          <div ref={chatEndRef} />
570	        </div>
571	      </div>
572	
573	      {/* Input Area */}
574	      <AnimatePresence>
575	        {!isTyping && currentStepData && (
576	          <motion.div
577	            initial={{ opacity: 0, y: 50 }}
578	            animate={{ opacity: 1, y: 0 }}
579	            exit={{ opacity: 0, y: 50 }}
580	            className="fixed bottom-0 left-0 right-0 bg-gradient-to-t from-background via-background to-transparent pt-8 pb-6 px-4"
581	          >
582	            <div className="max-w-2xl mx-auto">
583	              {(currentStepData.type === "options" || 
584	                currentStepData.type === "single-select" || 
585	                currentStepData.type === "multi-select") && (
586	                <div className="space-y-3">
587	                  <OptionButtons
588	                    options={currentStepData.options || []}
589	                    selected={selectedOptions}
590	                    onSelect={handleOptionSelect}
591	                    multiSelect={currentStepData.type === "multi-select"}
592	                  />
