12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
