75	serve(async (req) => {
76	  const cors = getCorsHeaders(req);
77	  if (req.method === 'OPTIONS') return new Response(null, { headers: cors });
78	
79	  try {
80	    // ── AUTH CHECK ──
81	    const authHeader = req.headers.get('Authorization');
82	    if (!authHeader) {
83	      return new Response(JSON.stringify({ error: 'Missing Authorization' }), { status: 401, headers: cors });
84	    }
85	
86	    const supabase = createClient(
87	      Deno.env.get('SUPABASE_URL')!,
88	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
89	    );
90	
91	    const token = authHeader.replace('Bearer ', '');
92	    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
93	    if (authError || !user) {
94	      return new Response(JSON.stringify({ error: 'Invalid Session' }), { status: 401, headers: cors });
95	    }
96	
97	    // ── REQUEST SIZE LIMIT ──
98	    const contentLength = req.headers.get('content-length');
99	    if (contentLength && parseInt(contentLength) > 20000) {
100	      return new Response(JSON.stringify({ error: 'Request too large' }), { status: 413, headers: cors });
101	    }
102	
103	    // ── PARSE & VALIDATE INPUT ──
104	    let body;
105	    try {
106	      body = await req.json();
107	    } catch {
108	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), { status: 400, headers: cors });
109	    }
110	
111	    const { messages } = body;
112	
113	    if (!messages || !Array.isArray(messages) || messages.length === 0) {
114	      return new Response(JSON.stringify({ error: 'Messages are required' }), { status: 400, headers: cors });
115	    }
116	
117	    // ── LIMIT MESSAGE HISTORY ──
118	    const recentMessages = messages.slice(-10);
119	
120	    // ── ABUSE DETECTION & SANITIZATION ──
121	    const lastMessage = recentMessages[recentMessages.length - 1];
122	    if (lastMessage?.content && isPromptAbuse(lastMessage.content)) {
123	      return new Response(JSON.stringify({
124	        reply: "I am Kira, built specifically for the creative economy. I cannot help with that, but I am here to help you grow your creative business. What do you need?"
125	      }), { status: 200, headers: { ...cors, 'Content-Type': 'application/json' } });
126	    }
127	
128	    const sanitizedMessages = recentMessages.map((msg: any) => ({
129	      role: msg.role,
130	      content: sanitizeMessage(msg.content || ''),
131	    }));
132	
133	    // ── CHECK DAILY LIMITS ──
134	    const { data: profile } = await supabase
135	      .from('profiles')
136	      .select('kira_tokens_used_today, kira_tokens_limit_daily')
137	      .eq('id', user.id)
138	      .single();
139	
140	    if (profile && profile.kira_tokens_used_today >= profile.kira_tokens_limit_daily) {
141	      return new Response(JSON.stringify({
142	        reply: "You have reached your daily Kira limit. Upgrade to Pro for 40 actions per day."
143	      }), { status: 200, headers: { ...cors, 'Content-Type': 'application/json' } });
144	    }
145	
146	    // ── CALL OPENAI ──
147	    const response = await fetch("https://api.openai.com/v1/chat/completions", {
148	      method: "POST",
149	      headers: {
150	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
151	        "Content-Type": "application/json",
152	      },
153	      body: JSON.stringify({
154	        model: "gpt-4o-mini",
155	        max_tokens: 1000,
156	        messages: [
157	          { role: "system", content: KIRA_SYSTEM_PROMPT },
158	          ...sanitizedMessages
159	        ],
160	      }),
161	    });
162	
163	    if (!response.ok) {
164	      throw new Error("OpenAI API error: " + response.status);
165	    }
166	
167	    const aiData = await response.json();
168	    const reply = aiData.choices?.[0]?.message?.content;
169	    const tokensUsed = aiData.usage?.total_tokens || 0;
170	
171	    if (!reply) {
172	      throw new Error('No response from AI');
173	    }
174	
175	    // ── UPDATE TOKEN COUNT ──
176	    await supabase.rpc('increment_kira_tokens', {
177	      user_id: user.id,
178	      tokens_to_add: tokensUsed
179	    });
180	
181	    return new Response(JSON.stringify({ reply }), {
182	      headers: { ...cors, 'Content-Type': 'application/json' }
183	    });
184	
185	  } catch (error) {
186	    console.error("Function Error:", error.message);
187	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
188	      status: 500, headers: cors
189	    });
190	  }
191	});
