1	import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
3	
4	const ALLOWED_ORIGINS = [
5	  'https://crevia.app',
6	  'https://www.crevia.app',
7	  'http://localhost:8080',
8	  'http://localhost:5173',
9	  'https://creviamvp.vercel.app',
10	];
11	
12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
20	}
21	
22	serve(async (req) => {
23	  const cors = getCorsHeaders(req);
24	
25	  if (req.method === 'OPTIONS') {
26	    return new Response(null, { headers: cors });
27	  }
28	
29	  try {
30	    const authHeader = req.headers.get('Authorization');
31	    if (!authHeader?.startsWith('Bearer ')) {
32	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
33	        status: 401,
34	        headers: { ...cors, 'Content-Type': 'application/json' },
35	      });
36	    }
37	
38	    const supabase = createClient(
39	      Deno.env.get('SUPABASE_URL')!,
40	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
41	    );
42	
43	    const token = authHeader.replace('Bearer ', '');
44	    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
45	    if (authError || !user) {
46	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
47	        status: 401,
48	        headers: { ...cors, 'Content-Type': 'application/json' },
49	      });
50	    }
51	
52	    const { type, profile, campaigns } = await req.json();
53	
54	    let systemPrompt = '';
55	    let userPrompt = '';
56	
57	    if (type === 'creator') {
58	      systemPrompt = `You are Kira AI, a personal agent for African creators. Provide personalized, actionable suggestions.
59	Suggest: best campaigns to apply to, profile improvements, pricing recommendations, collaboration opportunities.
60	Return ONLY a valid JSON array — no markdown, no explanation. Format: [{ "type": string, "title": string, "description": string, "action": string }]`;
61	      userPrompt = `Creator Profile: ${JSON.stringify(profile)}\nAvailable Campaigns: ${JSON.stringify(campaigns)}`;
62	    } else {
63	      systemPrompt = `You are Kira AI, a marketing strategist for brands working with African creators. Provide actionable suggestions.
64	Suggest: creator recommendations, budget optimization, brief improvements, audience targeting.
65	Return ONLY a valid JSON array — no markdown, no explanation. Format: [{ "type": string, "title": string, "description": string, "action": string }]`;
66	      userPrompt = `Brand Profile: ${JSON.stringify(profile)}\nCurrent Campaigns: ${JSON.stringify(campaigns)}`;
67	    }
68	
69	    const response = await fetch('https://api.openai.com/v1/chat/completions', {
70	      method: 'POST',
71	      headers: {
72	        'Authorization': `Bearer ${Deno.env.get('OPENAI_API_KEY')}`,
73	        'Content-Type': 'application/json',
74	      },
75	      body: JSON.stringify({
76	        model: 'gpt-4o-mini',
77	        max_tokens: 800,
78	        messages: [
79	          { role: 'system', content: systemPrompt },
80	          { role: 'user', content: userPrompt },
81	        ],
82	      }),
83	    });
84	
85	    if (!response.ok) {
86	      throw new Error(`OpenAI API error: ${response.status}`);
87	    }
