95	      if (!Array.isArray(suggestions)) suggestions = [];
96	    } catch {
97	      suggestions = [];
98	    }
99	
100	    return new Response(JSON.stringify({ suggestions }), {
101	      headers: { ...cors, 'Content-Type': 'application/json' },
102	    });
103	  } catch (error: unknown) {
104	    const msg = error instanceof Error ? error.message : String(error);
105	    console.error('kira-suggestions error:', msg);
106	    return new Response(JSON.stringify({ suggestions: [] }), {
107	      status: 200,
108	      headers: { ...cors, 'Content-Type': 'application/json' },
109	    });
110	  }
111	});
